def topo_sort(graph):
    in_degree = {n: 0 for n in graph}
    for node in graph:
        for neighbour in graph[node]:
            in_degree[neighbour] += 1
    queue = deque(n for n in in_degree if in_degree[n] == 0)
    result = []
    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbour in graph[node]:
            in_degree[neighbour] -= 1
            if in_degree[neighbour] == 0:
                queue.append(neighbour)
    return result

